// MARK: - SecretManager.swift
// Secure secret management - NEVER embed API keys directly in source code

import Foundation

enum SecretManagerError: Error {
    case missingSecret(String)
    case invalidConfiguration(String)
}

/// Manages application secrets securely.
/// Secrets are loaded from environment variables or a secure configuration file
/// that is NOT checked into source control.
final class SecretManager {
    static let shared = SecretManager()
    
    private var secrets: [String: String] = [:]
    
    private init() {
        loadSecrets()
    }
    
    // MARK: - Secret Keys
    
    enum Key: String {
        case googleMapsAPIKey = "GOOGLE_MAPS_API_KEY"
        case stripePublishableKey = "STRIPE_PUBLISHABLE_KEY"
        case stripeSecretKey = "STRIPE_SECRET_KEY"
    }
    
    // MARK: - Public API
    
    func secret(for key: Key) throws -> String {
        guard let value = secrets[key.rawValue], !value.isEmpty else {
            throw SecretManagerError.missingSecret(
                "Missing secret for '\(key.rawValue)'. " +
                "Set it via environment variable, Secrets.plist, or your CI/CD secret manager. " +
                "See README.md for setup instructions."
            )
        }
        return value
    }
    
    // MARK: - Loading Strategy (priority order)
    
    private func loadSecrets() {
        // Priority 1: Environment variables (works for CI/CD, Xcode schemes, and simulators)
        loadFromEnvironment()
        
        // Priority 2: Secrets.plist (local development file, MUST be in .gitignore)
        loadFromSecretsPlist()
        
        // Priority 3: Keychain (for previously stored secrets on-device)
        loadFromKeychain()
    }
    
    private func loadFromEnvironment() {
        for key in [Key.googleMapsAPIKey, Key.stripePublishableKey, Key.stripeSecretKey] {
            if let value = ProcessInfo.processInfo.environment[key.rawValue], !value.isEmpty {
                secrets[key.rawValue] = value
            }
        }
    }
    
    private func loadFromSecretsPlist() {
        // Secrets.plist must be listed in .gitignore
        guard let path = Bundle.main.path(forResource: "Secrets", ofType: "plist"),
              let dict = NSDictionary(contentsOfFile: path) as? [String: String] else {
            return
        }
        
        for (key, value) in dict where !value.isEmpty {
            // Don't overwrite environment variables (higher priority)
            if secrets[key] == nil {
                secrets[key] = value
            }
        }
    }
    
    private func loadFromKeychain() {
        for key in [Key.googleMapsAPIKey, Key.stripePublishableKey, Key.stripeSecretKey] {
            if secrets[key.rawValue] == nil {
                if let value = KeychainHelper.read(key: key.rawValue), !value.isEmpty {
                    secrets[key.rawValue] = value
                }
            }
        }
    }
    
    /// Store a secret in the Keychain for on-device persistence.
    /// Useful for demo setup screens where an investor enters keys once.
    func storeInKeychain(key: Key, value: String) {
        KeychainHelper.save(key: key.rawValue, value: value)
        secrets[key.rawValue] = value
    }
    
    /// Check if all required secrets are configured
    var isFullyConfigured: Bool {
        let requiredKeys: [Key] = [.googleMapsAPIKey, .stripePublishableKey]
        return requiredKeys.allSatisfy { key in
            (secrets[key.rawValue] ?? "").isEmpty == false
        }
    }
    
    /// Returns a list of missing required keys (for diagnostics)
    var missingKeys: [Key] {
        let requiredKeys: [Key] = [.googleMapsAPIKey, .stripePublishableKey]
        return requiredKeys.filter { key in
            (secrets[key.rawValue] ?? "").isEmpty
        }
    }
}

// MARK: - KeychainHelper.swift

import Security

enum KeychainHelper {
    
    static func save(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        // Delete existing item first
        let deleteQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrService as String: Bundle.main.bundleIdentifier ?? "com.app.secrets"
        ]
        SecItemDelete(deleteQuery as CFDictionary)
        
        // Add new item
        let addQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrService as String: Bundle.main.bundleIdentifier ?? "com.app.secrets",
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        SecItemAdd(addQuery as CFDictionary, nil)
    }
    
    static func read(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrService as String: Bundle.main.bundleIdentifier ?? "com.app.secrets",
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    static func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrService as String: Bundle.main.bundleIdentifier ?? "com.app.secrets"
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - AppDelegate.swift

import UIKit
import GoogleMaps
import Stripe

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
    ) -> Bool {
        
        let secretManager = SecretManager.shared
        
        if secretManager.isFullyConfigured {
            configureServices(with: secretManager)
            showMainApp()
        } else {
            // Show setup screen so the demo user can enter keys securely
            showSetupScreen()
        }
        
        return true
    }
    
    private func configureServices(with secretManager: SecretManager) {
        do {
            let googleMapsKey = try secretManager.secret(for: .googleMapsAPIKey)
            GMSServices.provideAPIKey(googleMapsKey)
            
            let stripeKey = try secretManager.secret(for: .stripePublishableKey)
            StripeAPI.defaultPublishableKey = stripeKey
        } catch {
            print("⚠️ Configuration error: \(error)")
            showSetupScreen()
        }
    }
    
    private func showMainApp() {
        window = UIWindow(frame: UIScreen.main.bounds)
        window?.rootViewController = MainViewController()
        window?.makeKeyAndVisible()
    }
    
    private func showSetupScreen() {
        window = UIWindow(frame: UIScreen.main.bounds)
        window?.rootViewController = UINavigationController(rootViewController: SetupViewController())
        window?.makeKeyAndVisible()
    }
}

