}

// MARK: - MainViewController.swift

import UIKit
import GoogleMaps

class MainViewController: UIViewController {
    
    private var mapView: GMSMapView!
    private let payButton = UIButton(type: .system)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Demo App"
        view.backgroundColor = .systemBackground
        setupMap()
        setupPayButton()
    }
    
    private func setupMap() {
        let options = GMSMapViewOptions()
        let camera = GMSCameraPosition.camera(
            withLatitude: 37.7749,
            longitude: -122.4194,
            zoom: 12.0
        )
        options.camera = camera
        options.frame = view.bounds
        
        mapView = GMSMapView(options: options)
        mapView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        view.addSubview(mapView)
        
        let marker = GMSMarker()
        marker.position = CLLocationCoordinate2D(latitude: 37.7749, longitude: -122.4194)
        marker.title = "San Francisco"
        marker.snippet = "Demo Location"
        marker.map = mapView
    }
    
    private func setupPayButton() {
        payButton.setTitle("Pay $9.99", for: .normal)
        payButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        payButton.backgroundColor = .systemGreen
        payButton.setTitleColor(.white, for: .normal)
        payButton.layer.cornerRadius = 12
        payButton.translatesAutoresizingMaskIntoConstraints = false
        payButton.addTarget(self, action: #selector(payTapped), for: .touchUpInside)
        
        view.addSubview(payButton)
        
        NSLayoutConstraint.activate([
            payButton.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -20),
            payButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            payButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            payButton.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
    
    @objc private func payTapped() {
        let paymentVC = PaymentViewController()
        let nav = UINavigationController(rootViewController: paymentVC)
        present(nav, animated: true)
    }
}

// MARK: - PaymentViewController.swift

import UIKit
import Stripe

class PaymentViewController: UIViewController {
    
    private lazy var cardTextField: STPPaymentCardTextField = {
        let field = STPPaymentCardTextField()
        field.translatesAutoresizingMaskIntoConstraints = false
        return field
    }()
    
    private let payButton = UIButton(type: .system)
    private let statusLabel = UILabel()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Payment"
        view.backgroundColor = .systemBackground
        navigationItem.leftBarButtonItem = UIBarButtonItem(
            barButtonSystemItem: .cancel, target: self, action: #selector(dismissVC)
        )
        setupUI()
    }
    
    private func setupUI() {
        statusLabel.textAlignment = .center
        statusLabel.numberOfLines = 0
        statusLabel.font = .systemFont(ofSize: 14)
        statusLabel.textColor = .secondaryLabel
        statusLabel.text = "Enter card details to complete payment"
        
        payButton.setTitle("Confirm Payment - $9.99", for: .normal)
        payButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        payButton.backgroundColor = .systemBlue
        payButton.setTitleColor(.white, for: .normal)
        payButton.layer.cornerRadius = 12
        payButton.addTarget(self, action: #selector(confirmPayment), for: .touchUpInside)
        
        let stackView = UIStackView(arrangedSubviews: [statusLabel, cardTextField, payButton])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -60),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            payButton.heightAnchor.constraint(equalToConstant: 50),
            cardTextField.heightAnchor.constraint(equalToConstant: 44)
        ])
    }
    
    @objc private func confirmPayment() {
        guard cardTextField.isValid else {
            statusLabel.text = "Please enter valid card details"
            statusLabel.textColor = .systemRed
            return
        }
        
        statusLabel.text = "Processing payment..."
        statusLabel.textColor = .systemBlue
        payButton.isEnabled = false
        
        let cardParams = cardTextField.cardParams
        let paymentMethodParams = STPPaymentMethodParams(
            card: STPPaymentMethodCardParams(cardSourceParams: cardParams),
            billingDetails: nil,
            metadata: nil
        )
        
        // In production, create a PaymentIntent on your backend server
        // and confirm it here with the client secret.
        // This demo shows the Stripe SDK integration pattern.
        statusLabel.text = "✅ Payment method created successfully!\n(Connect to backend for full processing)"
        statusLabel.textColor = .systemGreen
        payButton.isEnabled = true
    }
    
    @objc private func dismissVC() {
        dismiss(animated: true)
    }
}

